import{_ as t,c as o,o as i,ag as r}from"./chunks/framework.S-Qvb3wi.js";const m=JSON.parse('{"title":"DGrid Genesis Premium Exclusive Benefits","description":"","frontmatter":{},"headers":[],"relativePath":"Exclusive-Benefits.md","filePath":"Exclusive-Benefits.md"}'),s={name:"Exclusive-Benefits.md"};function a(n,e,c,d,l,u){return i(),o("div",null,e[0]||(e[0]=[r('<h1 id="dgrid-genesis-premium-exclusive-benefits" tabindex="-1">DGrid Genesis Premium Exclusive Benefits <a class="header-anchor" href="#dgrid-genesis-premium-exclusive-benefits" aria-label="Permalink to &quot;DGrid Genesis Premium Exclusive Benefits&quot;">​</a></h1><p>As early co-builders of the DGrid ecosystem, Genesis Members are entitled to comprehensive benefits covering economic rewards, resource access, product experience, and ecosystem co-construction. By deeply participating in network construction and governance, members can secure long-term and stable value returns. DGrid has allocated a dedicated reward pool from the total supply of $DGAI tokens to reciprocate members’ core contributions to network governance, ecosystem expansion, and AI service promotion, laying a solid foundation for the stable operation and high-quality development of the decentralized AI inference network.</p><p>In addition to the core $DGAI token rewards, Genesis Members can also enjoy diverse additional values brought by ecosystem development, including priority access to new products, discounts on AI services, and exclusive co-branding exposure. These benefits fully reflect the recognition of members’ support for the ecosystem and jointly maintain the vitality and security of the DGrid ecosystem.</p><p>The Genesis Premium Program opens the door for community members to deeply participate in the large-scale decentralized ecosystem of AI computing and inference services. Without requiring advanced technical capabilities or bearing high computing resource costs, anyone can easily tap into the decentralized AI economy and become a core part of the ecosystem’s development.</p><h2 id="detailed-breakdown-of-core-benefits" tabindex="-1">Detailed Breakdown of Core Benefits <a class="header-anchor" href="#detailed-breakdown-of-core-benefits" aria-label="Permalink to &quot;Detailed Breakdown of Core Benefits&quot;">​</a></h2><h3 id="_1-sustained-ecosystem-rewards" tabindex="-1">1. Sustained Ecosystem Rewards <a class="header-anchor" href="#_1-sustained-ecosystem-rewards" aria-label="Permalink to &quot;1. Sustained Ecosystem Rewards&quot;">​</a></h3><p>Holding the Genesis Premium status entitles members to sustained $DGAI ecosystem contribution rewards, as a token of appreciation for their support and participation in the early-stage network construction. Members will also automatically unlock additional airdrop rewards from ecosystem partners, sharing the long-term development dividends of the DGrid decentralized AI ecosystem.</p><h3 id="_2-priority-access-to-high-value-ai-models-apis" tabindex="-1">2. Priority Access to High-Value AI Models &amp; APIs <a class="header-anchor" href="#_2-priority-access-to-high-value-ai-models-apis" aria-label="Permalink to &quot;2. Priority Access to High-Value AI Models &amp; APIs&quot;">​</a></h3><p>From the date of joining, members can access enterprise-grade AI service resources that perfectly meet the needs of developers and advanced users:</p><ul><li>A monthly platform credit line equivalent to $300</li><li>100 free calls to selected models per day</li><li>Priority access to high-demand, large-scale AI models</li><li>Enhanced rate limits to ensure stable and uninterrupted service operation</li></ul><h3 id="_3-exclusive-governance-rights" tabindex="-1">3. Exclusive Governance Rights <a class="header-anchor" href="#_3-exclusive-governance-rights" aria-label="Permalink to &quot;3. Exclusive Governance Rights&quot;">​</a></h3><p>Members are granted weighted voting rights in key decision-making scenarios, including network protocol adjustments, treasury fund allocation, and model integration proposals. They can participate in closed-door governance seminars, engage in direct dialogue with the core team and other co-builders, and turn their opinions into tangible influence on the ecosystem’s development.</p><h3 id="_4-priority-experience-of-new-products-features" tabindex="-1">4. Priority Experience of New Products &amp; Features <a class="header-anchor" href="#_4-priority-experience-of-new-products-features" aria-label="Permalink to &quot;4. Priority Experience of New Products &amp; Features&quot;">​</a></h3><p>Members get early access to Alpha/Beta versions of new products, core infrastructure functions, and development tools. They can join the core team’s closed-door feedback mechanism, provide suggestions based on their practical usage experience, contribute to product optimization and upgrades, and jointly shape product forms that align with user needs.</p><h3 id="_5-priority-for-ecosystem-co-construction" tabindex="-1">5. Priority for Ecosystem Co-Construction <a class="header-anchor" href="#_5-priority-for-ecosystem-co-construction" aria-label="Permalink to &quot;5. Priority for Ecosystem Co-Construction&quot;">​</a></h3><p>When applying to list AI models or launch intelligent agent services on the DGrid Marketplace, members enjoy priority review and onboarding eligibility. They also have priority selection rights for roles related to network infrastructure, such as node operation and computing resource supply, enabling them to deeply participate in the core links of ecosystem construction.</p>',16)]))}const h=t(s,[["render",a]]);export{m as __pageData,h as default};
